-- ============================================================================
-- MemberJunction PostgreSQL Migration
-- Converted from SQL Server using TypeScript conversion pipeline
-- ============================================================================

-- Extensions
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Schema
CREATE SCHEMA IF NOT EXISTS __mj;
SET search_path TO __mj, public;

-- Ensure backslashes in string literals are treated literally (not as escape sequences)
SET standard_conforming_strings = on;

-- NOTE: Earlier converter versions made INTEGER to BOOLEAN cast implicit by
-- modifying the system catalog so SS-style INSERT INTO bool_col VALUES (1)
-- would work. That modification required pg_catalog write privileges, which
-- managed PG (RDS, Aurora, Cloud SQL, Azure) does not grant. As of v5.30 all
-- bulk INSERTs are emitted with native TRUE/FALSE values directly, so the
-- cast modification is no longer needed. Removed to support managed-PG
-- installs out of the box.


-- ===================== DDL: Tables, PKs, Indexes =====================

-- Artifact / Attachment Unification
--
-- Schema and one-time data migration unifying the two parallel file-delivery
-- paths in MJ's AI agent runtime (ConversationDetailAttachment inline embedding
-- vs. ConversationArtifactVersion + tool dispatch). See
-- plans/artifact-attachment-unification.md for the design.
--
-- All schema additions are additive (defaults preserve existing behavior):
--
-- ArtifactType:
--   Priority             — deterministic tiebreaker for MIME pattern resolution
--   DefaultDeliveryMode  — Inline vs ToolsOnly delivery policy per type
--   SystemSupplied       — distinguishes shipped defaults from org customizations
--
-- ArtifactVersion:
--   ForceToolsOnly       — one-way per-instance opt-out of inline delivery
--                          (lives on ArtifactVersion alongside MimeType/FileID/
--                          ContentSizeBytes, where the resolver routes from)
--
-- AIAgent:
--   AcceptUnregisteredFiles — per-agent opt-in to a Generic Binary fallback for
--                             MIME types outside the registered Artifact Type set
--
-- ConversationDetailAttachment:
--   ArtifactVersionID    — FK to the ArtifactVersion created alongside this
--                          attachment by the storage-unification path. Set when
--                          attachments are written through the unified service;
--                          NULL for pre-unification rows. Lets the resolver
--                          skip attachments that already have an artifact path.
--
-- AIAgentRunStep:
--   StepType             — CHECK constraint widened to include 'Tool' so artifact
--                          tool calls (and future tool mechanisms whose dispatch
--                          is higher-order than Actions) record as first-class
--                          run steps with their own InputData / OutputData rather
--                          than being buried inside the parent Prompt step's
--                          OutputData blob. Step naming convention (enforced in
--                          base-agent, not the DB): each step created for an
--                          artifact tool call uses StepName='Artifact Tool: {toolName}'.
--
-- Seed data (new system Artifact Type rows: BYTEA, Audio, Video, XML, CSV,
-- Generic Text, Generic Binary; plus DefaultDeliveryMode/SystemSupplied values
-- for existing rows) lives in /metadata/artifact-types/ and is applied via
-- `mj sync push`, not this migration.
--
-- Data backfill (idempotent) at the bottom of this file: existing attachments
-- get paired with Artifact + ArtifactVersion + junction rows, and legacy rows
-- previously classified under the deleted JSON_ARTIFACT_TYPE_ID fallback are
-- reclassified to Generic Text or Generic Binary based on ISJSON() / ContentMode.
-- Both phases are no-ops on a fresh database (no attachments yet, fallback type
-- not present); they exist for the upgrade path from pre-v5.35 installs.

-- =====================================================
-- Schema changes
-- =====================================================

ALTER TABLE __mj."ArtifactType"
 ADD COLUMN IF NOT EXISTS "Priority" INTEGER NOT NULL CONSTRAINT DF_ArtifactType_Priority DEFAULT 0,
 ADD COLUMN IF NOT EXISTS "DefaultDeliveryMode" VARCHAR(20) NOT NULL CONSTRAINT DF_ArtifactType_DefaultDeliveryMode DEFAULT 'ToolsOnly'
            CONSTRAINT CK_ArtifactType_DefaultDeliveryMode CHECK ("DefaultDeliveryMode" IN ('Inline', 'ToolsOnly')),
 ADD COLUMN IF NOT EXISTS "SystemSupplied" BOOLEAN NOT NULL CONSTRAINT DF_ArtifactType_SystemSupplied DEFAULT FALSE;

ALTER TABLE __mj."ArtifactVersion"
 ADD COLUMN IF NOT EXISTS "ForceToolsOnly" BOOLEAN NOT NULL CONSTRAINT DF_ArtifactVersion_ForceToolsOnly DEFAULT FALSE;

ALTER TABLE __mj."AIAgent"
 ADD COLUMN IF NOT EXISTS "AcceptUnregisteredFiles" BOOLEAN NOT NULL CONSTRAINT DF_AIAgent_AcceptUnregisteredFiles DEFAULT FALSE;

ALTER TABLE __mj."ConversationDetailAttachment"
 ADD COLUMN IF NOT EXISTS "ArtifactVersionID" UUID NULL
        CONSTRAINT FK_ConversationDetailAttachment_ArtifactVersion
            REFERENCES __mj."ArtifactVersion"("ID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_ParentID" ON __mj."AIAgent" ("ParentID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_ContextCompressionPromptID" ON __mj."AIAgent" ("ContextCompressionPromptID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_TypeID" ON __mj."AIAgent" ("TypeID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_DefaultArtifactTypeID" ON __mj."AIAgent" ("DefaultArtifactTypeID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_OwnerUserID" ON __mj."AIAgent" ("OwnerUserID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_AttachmentStorageProviderID" ON __mj."AIAgent" ("AttachmentStorageProviderID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_CategoryID" ON __mj."AIAgent" ("CategoryID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_AIAgent_DefaultStorageAccountID" ON __mj."AIAgent" ("DefaultStorageAccountID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ArtifactType_ParentID" ON __mj."ArtifactType" ("ParentID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ArtifactVersion_ArtifactID" ON __mj."ArtifactVersion" ("ArtifactID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ArtifactVersion_UserID" ON __mj."ArtifactVersion" ("UserID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ArtifactVersion_FileID" ON __mj."ArtifactVersion" ("FileID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ConversationDetailAttachment_Conversa_cf82ff61" ON __mj."ConversationDetailAttachment" ("ConversationDetailID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ConversationDetailAttachment_ModalityID" ON __mj."ConversationDetailAttachment" ("ModalityID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ConversationDetailAttachment_FileID" ON __mj."ConversationDetailAttachment" ("FileID");

CREATE INDEX IF NOT EXISTS "IDX_AUTO_MJ_FKEY_ConversationDetailAttachment_ArtifactVersionID" ON __mj."ConversationDetailAttachment" ("ArtifactVersionID");


-- ===================== Helper Functions (fn*) =====================

DO $$ DECLARE r record;
BEGIN
  FOR r IN SELECT oid::regprocedure AS sig FROM pg_proc
           WHERE proname = 'fnAIAgentParentID_GetRootID'
             AND pronamespace = '__mj'::regnamespace
  LOOP EXECUTE 'DROP FUNCTION IF EXISTS ' || r.sig || ' CASCADE';
  END LOOP;
END $$;
CREATE OR REPLACE FUNCTION __mj."fnAIAgentParentID_GetRootID"(
    p_RecordID UUID,
    p_ParentID UUID
)
RETURNS TABLE("RootID" UUID) AS $$
WITH RECURSIVE CTE_RootParent AS (
        SELECT
            "ID",
            "ParentID",
            "ID" AS "RootParentID",
            0 AS "Depth"
        FROM
            __mj."AIAgent"
        WHERE
            "ID" = COALESCE(p_ParentID, p_RecordID)

        UNION ALL

        SELECT
            c."ID",
            c."ParentID",
            c."ID" AS "RootParentID",
            p."Depth" + 1 AS "Depth"
        FROM
            __mj."AIAgent" c
        INNER JOIN
            CTE_RootParent p ON c."ID" = p."ParentID"
        WHERE
            p."Depth" < 100
    )
    SELECT         "RootParentID" AS RootID
    FROM
        CTE_RootParent
    WHERE
        "ParentID" IS NULL
    ORDER BY
        "RootParentID"

LIMIT 1
$$ LANGUAGE sql;

DO $$ DECLARE r record;
BEGIN
  FOR r IN SELECT oid::regprocedure AS sig FROM pg_proc
           WHERE proname = 'fnArtifactTypeParentID_GetRootID'
             AND pronamespace = '__mj'::regnamespace
  LOOP EXECUTE 'DROP FUNCTION IF EXISTS ' || r.sig || ' CASCADE';
  END LOOP;
END $$;
CREATE OR REPLACE FUNCTION __mj."fnArtifactTypeParentID_GetRootID"(
    p_RecordID UUID,
    p_ParentID UUID
)
RETURNS TABLE("RootID" UUID) AS $$
WITH RECURSIVE CTE_RootParent AS (
        SELECT
            "ID",
            "ParentID",
            "ID" AS "RootParentID",
            0 AS "Depth"
        FROM
            __mj."ArtifactType"
        WHERE
            "ID" = COALESCE(p_ParentID, p_RecordID)

        UNION ALL

        SELECT
            c."ID",
            c."ParentID",
            c."ID" AS "RootParentID",
            p."Depth" + 1 AS "Depth"
        FROM
            __mj."ArtifactType" c
        INNER JOIN
            CTE_RootParent p ON c."ID" = p."ParentID"
        WHERE
            p."Depth" < 100
    )
    SELECT         "RootParentID" AS RootID
    FROM
        CTE_RootParent
    WHERE
        "ParentID" IS NULL
    ORDER BY
        "RootParentID"

LIMIT 1
$$ LANGUAGE sql;


