DO $mj$
DECLARE
    v_constraint_name TEXT;
BEGIN
    SELECT c.conname INTO v_constraint_name
    FROM pg_constraint c
    JOIN pg_attribute a ON a.attrelid = c.conrelid AND a.attnum = ANY(c.conkey)
    WHERE c.conrelid = '__mj."AIAgentRunStep"'::regclass
      AND a.attname = 'StepType'
      AND c.contype = 'c';
    IF v_constraint_name IS NOT NULL THEN
        EXECUTE format('ALTER TABLE __mj."AIAgentRunStep" DROP CONSTRAINT %I', v_constraint_name);
        RAISE NOTICE 'Dropped existing StepType check constraint: %', v_constraint_name;
    END IF;
